"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   categories: () => (/* binding */ categories),\n/* harmony export */   difficulties: () => (/* binding */ difficulties),\n/* harmony export */   getDailyRiddle: () => (/* binding */ getDailyRiddle),\n/* harmony export */   getRelatedRiddles: () => (/* binding */ getRelatedRiddles),\n/* harmony export */   getRiddleBySlug: () => (/* binding */ getRiddleBySlug),\n/* harmony export */   getRiddlesByCategory: () => (/* binding */ getRiddlesByCategory),\n/* harmony export */   riddles: () => (/* binding */ riddles)\n/* harmony export */ });\nconst riddles = [\n    // ═══════════════════════════════════════════\n    // CLASSIC\n    // ═══════════════════════════════════════════\n    {\n        id: \"echo\",\n        slug: \"echo-speaks-without-mouth\",\n        question: \"I speak without a mouth and hear without ears. I have no body, but I come alive with the wind. What am I?\",\n        answer: \"An Echo\",\n        explanation: \"Sound waves bounce off hard surfaces and return to the listener. Without any physical form, an echo appears to speak and respond purely through the movement of air.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"sound\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"footsteps\",\n        slug: \"more-you-take-leave-behind\",\n        question: \"The more you take, the more you leave behind. What am I?\",\n        answer: \"Footsteps\",\n        explanation: \"Each step you take creates a footprint behind you. The more steps you take, the more you leave — you can never pick them back up.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"movement\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"candle\",\n        slug: \"taller-younger-shorter-older\",\n        question: \"The taller I am, the younger I grow. The shorter I become, the older I am. What am I?\",\n        answer: \"A Candle\",\n        explanation: \"A brand new candle stands tall. As it burns and ages, it gets shorter. The taller it is, the newer it is — and the shorter it gets, the more of its life has been consumed.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"time\"\n        ]\n    },\n    {\n        id: \"silence\",\n        slug: \"break-without-touching\",\n        question: \"What can you break, even if you never pick it up or touch it?\",\n        answer: \"Silence\",\n        explanation: \"Silence can be broken simply by making any sound — no physical contact required. A single word or whisper shatters it completely.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"abstract\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"fire\",\n        slug: \"eat-and-live-water-die\",\n        question: \"I eat and live. Give me water and I die. I bring warmth but also destruction. What am I?\",\n        answer: \"Fire\",\n        explanation: \"Fire consumes fuel to stay alive. Water extinguishes it. It provides warmth and light but can also burn and destroy everything around it.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"elements\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"mirror\",\n        slug: \"never-lies-always-reversed\",\n        question: \"I show you the world but everything I show you is reversed. I am still when you are still and move when you move. What am I?\",\n        answer: \"A Mirror\",\n        explanation: \"A mirror reflects an accurate image but flips everything left-to-right. It perfectly copies your movements in real time.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"reflection\"\n        ]\n    },\n    {\n        id: \"clock\",\n        slug: \"hands-cannot-clap-face-no-eyes\",\n        question: \"I have hands but I cannot clap. I have a face but no eyes to see. I tell you something every moment of the day yet I never speak a word. What am I?\",\n        answer: \"A Clock\",\n        explanation: \"A clock has hands that point to numbers and a face — but these are metaphors. It communicates the time constantly through its display without ever making a sound.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"time\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"river\",\n        slug: \"bed-never-sleep-mouth-never-eat\",\n        question: \"I have a bed but never sleep, a mouth but never eat. I run all day but never tire. What am I?\",\n        answer: \"A River\",\n        explanation: \"A riverbed is the ground beneath the water. Rivers have mouths where they meet the sea. They flow constantly — but none of these are the human features they resemble.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nature\",\n            \"water\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"shadow\",\n        slug: \"follow-by-day-vanish-at-night\",\n        question: \"I follow you by day but vanish at night. I copy your every move but have no will of my own. What am I?\",\n        answer: \"A Shadow\",\n        explanation: \"Your shadow mimics your movements exactly but disappears in darkness. It is long when the sun is low and short when it is directly overhead.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"light\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"key\",\n        slug: \"small-opens-great-things\",\n        question: \"I am small but I can open great things. I have no power of my own, yet nothing opens without me. I am cut and shaped for one purpose only. What am I?\",\n        answer: \"A Key\",\n        explanation: \"A key is a small metal object that unlocks doors, vaults, and safes. It has no power itself but enables everything. Each key is uniquely cut to fit one specific lock.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"book\",\n        slug: \"leaves-no-roots-spine-no-bones\",\n        question: \"I have hundreds of leaves but no roots or branches. I have a spine but no bones. Open me and worlds appear. Close me and they vanish. What am I?\",\n        answer: \"A Book\",\n        explanation: \"A book's leaves are its pages and its spine is the bound edge — neither are real leaves or bones. Open a book and entire worlds come to life through your imagination.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"classic\",\n            \"reading\"\n        ]\n    },\n    {\n        id: \"newspaper\",\n        slug: \"black-white-read-all-over\",\n        question: \"I am black and white and read all over. I am filled with stories but I cannot speak. I age quickly but I never move. What am I?\",\n        answer: \"A Newspaper\",\n        explanation: \"A newspaper is printed in black ink on white paper and is read all over — a classic pun on the word red. It contains stories but is silent, and becomes outdated very quickly.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"classic\",\n            \"wordplay\"\n        ]\n    },\n    {\n        id: \"hole\",\n        slug: \"more-you-remove-larger-i-grow\",\n        question: \"The more you remove from me, the larger I become. What am I?\",\n        answer: \"A Hole\",\n        explanation: \"When you dig out or remove material from a hole, it gets bigger. The act of taking away is exactly what makes it grow — the opposite of almost everything else.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"lateral\"\n        ]\n    },\n    {\n        id: \"anchor\",\n        slug: \"holds-great-weight-without-hands\",\n        question: \"I hold great weight without hands or arms. I live at the bottom but rule from below. I am heavy when needed and useless otherwise. What am I?\",\n        answer: \"An Anchor\",\n        explanation: \"An anchor holds a ship in place using its weight and grip on the seabed — no hands required. It sits at the bottom of the water keeping the whole vessel under control.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nautical\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"lightning\",\n        slug: \"strikes-without-warning-illuminates-everything\",\n        question: \"I strike without warning, illuminate everything for a moment, then disappear without a trace. I am feared yet beautiful. What am I?\",\n        answer: \"Lightning\",\n        explanation: \"Lightning strikes with no warning, lights up the entire sky instantly, then vanishes. It is both terrifying and spectacular. The saying it never strikes twice is actually a myth — tall objects are struck repeatedly.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"weather\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"wind\",\n        slug: \"feel-but-cannot-see-travels-everywhere\",\n        question: \"You feel me but cannot see me. I can be gentle or violent. I have no home yet I travel everywhere. I carry seeds, scatter leaves, and shape mountains over time. What am I?\",\n        answer: \"The Wind\",\n        explanation: \"Wind is invisible but felt on skin. It ranges from a gentle breeze to a hurricane. It disperses seeds, strips trees of leaves, and over millennia erodes and sculpts entire mountain ranges.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"weather\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"compass\",\n        slug: \"always-points-north-no-opinion\",\n        question: \"I always point north but have no opinion. I guide without moving. I am lost without the earth's invisible force. What am I?\",\n        answer: \"A Compass\",\n        explanation: \"A compass needle always aligns with Earth's magnetic field, pointing north. It guides travellers without moving itself. Without Earth's magnetic field, it would be useless.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"navigation\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"coin\",\n        slug: \"two-faces-one-speaks\",\n        question: \"I have two faces but only one is shown at a time. I am flipped in moments of indecision. I am small but I built empires. What am I?\",\n        answer: \"A Coin\",\n        explanation: \"A coin has heads and tails — two faces. Flipping a coin is a classic way to make decisions by chance. Throughout history, coinage has been the foundation of entire economies and empires.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"money\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"star\",\n        slug: \"shines-brightest-in-dark-burned-billions-years\",\n        question: \"I shine brightest in the dark. I have burned for billions of years yet you can cover me with your thumb. I am enormously far away yet I guide sailors home. What am I?\",\n        answer: \"A Star\",\n        explanation: \"Stars are only visible at night. They burn as nuclear furnaces for billions of years. Despite their incomprehensible size and distance, you can block one from view with your thumb. The North Star has guided navigators for millennia.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nature\",\n            \"space\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"dice\",\n        slug: \"six-faces-one-shown-decide-fate\",\n        question: \"I have six faces but only one is ever shown at a time. I have no voice but I decide your fate in games. What am I?\",\n        answer: \"A Die\",\n        explanation: \"A standard die has six faces. Only one faces up at any time. In games, the number rolled determines your next move — deciding your fortune in the game.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"games\"\n        ]\n    },\n    {\n        id: \"tooth\",\n        slug: \"sharp-when-young-blunt-with-age\",\n        question: \"I am sharp when I am young. I grow blunt with age. I help you devour things yet I can fall out. Replace me and I return — once. What am I?\",\n        answer: \"A Tooth\",\n        explanation: \"Baby teeth are sharp and new. They wear down with use. We get two sets of teeth in a lifetime — lose your baby teeth and adult ones grow. Lose those, and they are gone for good.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"body\",\n            \"nature\"\n        ]\n    },\n    {\n        id: \"wine\",\n        slug: \"better-with-age-ruined-by-heat\",\n        question: \"I get better with age but am ruined by heat. I am treasured when old but ignored when young. I come from grapes or grain. What am I?\",\n        answer: \"Wine\",\n        explanation: \"Wine improves over years in the barrel or bottle. Heat spoils it. A fine aged bottle is celebrated while cheap young wine is overlooked. Made from fermented grapes or grains.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"food\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"ladder\",\n        slug: \"i-go-up-but-never-move\",\n        question: \"I help you rise but I never move myself. I stand straight and yet I lean. Climb me and you reach somewhere new. What am I?\",\n        answer: \"A Ladder\",\n        explanation: \"A ladder stays still while you climb it. It leans against a wall and allows you to reach heights you could not otherwise achieve on your own.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"glove\",\n        slug: \"five-rooms-no-doors-no-windows\",\n        question: \"I have five rooms but no doors and no windows. Every room is empty yet something lives inside. What am I?\",\n        answer: \"A Glove\",\n        explanation: \"A glove has five finger slots — the five rooms — and no doors or windows. When worn, your fingers fill each empty chamber.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"clothing\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"needle\",\n        slug: \"eye-but-cannot-see-thread-the-world\",\n        question: \"I have an eye but cannot see. I am sharp at one end and hollow at the other. I help hold things together. What am I?\",\n        answer: \"A Needle\",\n        explanation: \"A sewing needle has a small hole called an eye through which thread is passed. It is sharp at the tip and the eye is hollow. It is used to stitch fabric together.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"classic\",\n            \"sewing\"\n        ]\n    },\n    {\n        id: \"envelope\",\n        slug: \"tongue-cannot-taste-carries-messages\",\n        question: \"I have a tongue but cannot taste. I carry messages but never speak. Lick me and I seal myself. What am I?\",\n        answer: \"An Envelope\",\n        explanation: \"An envelope has a flap — the tongue — that you lick to seal it. It carries letters and messages but has no voice of its own.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"wordplay\"\n        ]\n    },\n    {\n        id: \"bridge\",\n        slug: \"cross-me-every-day-but-never-get-wet\",\n        question: \"Thousands cross me every day but I never move. I span great distances yet I never travel. What am I?\",\n        answer: \"A Bridge\",\n        explanation: \"A bridge is a fixed structure that allows people and vehicles to cross water or valleys. Thousands of people cross it daily but the bridge itself never moves.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"structures\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"umbrella\",\n        slug: \"only-useful-when-open-protects-from-above\",\n        question: \"I am useless when closed and useful only when open. I protect you from above but I do not cover your feet. What am I?\",\n        answer: \"An Umbrella\",\n        explanation: \"An umbrella must be opened to serve its purpose — a closed umbrella keeps nothing dry. It shields you from rain or sun from above, but leaves your feet exposed.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"objects\",\n            \"weather\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"stairs\",\n        slug: \"always-going-up-never-going-down\",\n        question: \"I go up but I never come down. I am always climbed but I never move. I exist only between two levels. What am I?\",\n        answer: \"A Staircase\",\n        explanation: \"A staircase is a fixed structure for ascending or descending between floors. While people go both up and down on stairs, the stairs themselves remain stationary.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"structures\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"match\",\n        slug: \"born-in-the-dark-dies-in-the-light\",\n        question: \"I am born in darkness and die when brought to light. I feed the room with my brightness but consume myself in doing so. What am I?\",\n        answer: \"A Match\",\n        explanation: \"A match lives in darkness in its box and is born — ignited — when struck. It dies as it burns down, and in the process gives light to those around it.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"fire\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"shoes\",\n        slug: \"come-in-pairs-never-same-foot\",\n        question: \"I come in pairs but you never use both at the same time on the same foot. I protect you from the ground but the ground is all I touch. What am I?\",\n        answer: \"Shoes\",\n        explanation: \"Shoes come in pairs — one for each foot. You wear one on each foot simultaneously, but neither shoe ever touches the same foot as the other. They protect your feet yet make constant contact with the floor.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"clothing\",\n            \"objects\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"rain\",\n        slug: \"falls-never-injured-runs-no-legs\",\n        question: \"I fall but I am never injured. I run but I have no legs. I come from above and end up below. I am needed by all living things. What am I?\",\n        answer: \"Rain\",\n        explanation: \"Rain falls from clouds but never gets hurt by the landing. It runs along gutters and streams but has no legs. All plants and animals depend on rain to survive.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"weather\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"mountain\",\n        slug: \"older-than-any-king-never-moves\",\n        question: \"I am older than any king yet I bow to no one. I cannot move yet I have shaped the world. The higher you climb me the colder it gets. What am I?\",\n        answer: \"A Mountain\",\n        explanation: \"Mountains have existed for millions of years — far older than any human civilisation. They are immovable yet have determined the course of history, migration, and weather patterns. Temperature drops as altitude increases.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"geography\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"moon\",\n        slug: \"born-full-dies-thin-reborn-again\",\n        question: \"I grow full then thin then disappear then return again. I light the night but I make no light of my own. I pull the ocean but I cannot touch it. What am I?\",\n        answer: \"The Moon\",\n        explanation: \"The moon waxes to a full circle then wanes to nothing across its cycle before returning. It reflects sunlight rather than generating its own. Its gravitational pull creates the tides despite being nearly 240,000 miles away.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nature\",\n            \"space\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"sun\",\n        slug: \"everyone-sees-nobody-can-look-directly\",\n        question: \"Everyone sees me every day but nobody can look directly at me. I rise every morning and die every night yet I never truly disappear. What am I?\",\n        answer: \"The Sun\",\n        explanation: \"The sun is visible every day but staring directly at it damages your eyes. It rises at dawn and sets at dusk but never actually dies — it simply moves below the horizon to illuminate the other side of the Earth.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"space\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"ice\",\n        slug: \"born-in-water-killed-by-heat\",\n        question: \"I am born from water and killed by warmth. I am hard to the touch but soft in defeat. I float on the very thing I came from. What am I?\",\n        answer: \"Ice\",\n        explanation: \"Ice forms when water freezes. It melts back to water when warmed. Ice is hard and solid until heat defeats it. Uniquely, ice floats on liquid water because it is less dense than the liquid form.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"water\",\n            \"elements\"\n        ]\n    },\n    {\n        id: \"cloud\",\n        slug: \"lighter-than-feather-heavier-than-elephant\",\n        question: \"I am lighter than a feather yet I carry millions of tonnes. I have no shape yet I take every shape. I float even though I am enormously heavy. What am I?\",\n        answer: \"A Cloud\",\n        explanation: \"Individual water droplets in a cloud are incredibly light. Yet a typical cumulus cloud contains around 500 tonnes of water. Clouds float because their droplets fall so slowly they are kept aloft by rising air currents.\",\n        category: \"classic\",\n        difficulty: \"hard\",\n        tags: [\n            \"nature\",\n            \"weather\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"eye\",\n        slug: \"window-to-world-blind-in-dark\",\n        question: \"I am the window through which you see the world. I never lie yet I am always deceived. Cover me and your world goes dark. What am I?\",\n        answer: \"An Eye\",\n        explanation: \"The eye is how we perceive the world visually. Yet optical illusions show that our eyes can be easily tricked — we see what our brain expects rather than reality. Close or cover the eye and vision disappears.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"body\",\n            \"senses\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"tongue\",\n        slug: \"no-bones-strongest-muscle-wounds-without-blood\",\n        question: \"I have no bones yet I am one of the strongest muscles. I help you eat and speak. I can wound without drawing blood. What am I?\",\n        answer: \"The Tongue\",\n        explanation: \"The tongue contains no bones but is a remarkably strong and flexible muscle. It is essential for chewing, swallowing and speech. Harsh words spoken by the tongue can cause lasting emotional pain without any physical wound.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"body\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"heart\",\n        slug: \"beats-all-your-life-never-rests\",\n        question: \"I beat all your life and never rest. Stop me and everything stops. I am the size of your fist but I power everything. What am I?\",\n        answer: \"The Heart\",\n        explanation: \"The human heart beats continuously from before birth until death — roughly three billion times in a lifetime. If it stops, life ceases. Despite being approximately the size of a fist, it powers the entire circulatory system.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"body\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"lungs\",\n        slug: \"two-of-us-never-touch-breathe-together\",\n        question: \"There are two of us and we never touch each other. We work together all day and night. We take in the invisible and give back the invisible. What are we?\",\n        answer: \"Lungs\",\n        explanation: \"The two lungs sit side by side separated by the heart and never actually touch. They work in constant rhythm, inhaling oxygen and exhaling carbon dioxide — both invisible.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"body\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"bone\",\n        slug: \"harder-than-wood-alive-inside\",\n        question: \"I am harder than wood yet I am alive. I hold you up but you cannot see me. Break me and I heal — but slowly. What am I?\",\n        answer: \"A Bone\",\n        explanation: \"Bone is harder than most wood yet is living tissue filled with marrow and nerves. The skeleton is hidden beneath skin and muscle. Broken bones knit back together over weeks.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"body\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"blood\",\n        slug: \"travels-whole-body-never-stops\",\n        question: \"I travel the entire body every minute of the day. I carry life to every corner. I am red but I started darker. What am I?\",\n        answer: \"Blood\",\n        explanation: \"Blood circulates continuously around the body carrying oxygen, nutrients, and immune cells to every organ. Blood appears bright red when oxygenated and dark red when deoxygenated.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"body\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"breath\",\n        slug: \"use-every-moment-rarely-think-about\",\n        question: \"You use me every moment of your life yet you rarely think of me. I am invisible but essential. Take me away and nothing survives. What am I?\",\n        answer: \"Breath\",\n        explanation: \"We breathe around 20,000 times a day almost entirely without conscious thought. Air is invisible yet completely essential — all life ceases within minutes without it.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"life\",\n            \"body\"\n        ]\n    },\n    {\n        id: \"egg\",\n        slug: \"house-no-doors-golden-treasure\",\n        question: \"A house with no doors, no windows, and a golden treasure inside. What am I?\",\n        answer: \"An Egg\",\n        explanation: \"An egg has a shell that acts as a sealed house with no openings. Inside is the golden yolk — the treasure. It is one of the oldest riddles in the world.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"food\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"onion\",\n        slug: \"more-layers-peel-more-you-weep\",\n        question: \"The more layers you remove, the more you weep. I am essential in cooking and hated when raw. What am I?\",\n        answer: \"An Onion\",\n        explanation: \"Peeling an onion releases compounds that irritate the eyes, causing tears. Onions are essential in cooking worldwide but are rarely enjoyed raw.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"food\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"apple\",\n        slug: \"teacher-favourite-doctor-enemy\",\n        question: \"Red on the outside, white on the inside, with seeds at the centre. A teacher's favourite, a doctor's enemy. What am I?\",\n        answer: \"An Apple\",\n        explanation: \"A red apple has white flesh and seeds at its core. The saying an apple a day keeps the doctor away — and the tradition of giving apples to teachers — makes this a classic riddle.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"food\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"bread\",\n        slug: \"rise-without-legs-heat-to-become\",\n        question: \"I rise without legs. I need heat to become what I am. I start soft, become hard, then return to soft. What am I?\",\n        answer: \"Bread\",\n        explanation: \"Bread dough rises as yeast produces carbon dioxide. It bakes in heat to form a firm crust. Once cut and left exposed, the crust softens again over time.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"food\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"salt\",\n        slug: \"preserved-armies-started-wars-seasoned-meals\",\n        question: \"I have preserved armies, started wars, and seasoned every meal in history. I am invisible when dissolved but always felt. What am I?\",\n        answer: \"Salt\",\n        explanation: \"Salt was so valuable in ancient times that Roman soldiers were partially paid in it — the origin of the word salary. It preserved food before refrigeration and is essential in cooking across every culture.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"food\",\n            \"history\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"fire2\",\n        slug: \"daughter-of-water-kills-mother\",\n        question: \"I am the daughter of water yet when water touches me I die. What am I?\",\n        answer: \"Fire\",\n        explanation: \"This beautiful riddle plays on the relationship between fire and water. Fire requires water vapour in nature — in a sense water is its parent — yet liquid water extinguishes it instantly.\",\n        category: \"classic\",\n        difficulty: \"hard\",\n        tags: [\n            \"elements\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"darkness\",\n        slug: \"always-with-you-night-flees-smallest-light\",\n        question: \"I am always with you in the night. I flee from the smallest light. I am not evil — I am simply the absence of something. What am I?\",\n        answer: \"Darkness\",\n        explanation: \"Darkness is simply the absence of light. It accompanies the night universally and disappears at the first source of light.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nature\",\n            \"abstract\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"smoke\",\n        slug: \"no-shape-fills-any-room-born-from-fire\",\n        question: \"I have no shape of my own yet I fill any room. I cannot be held yet I choke those who breathe me. I am born from fire but I am not fire. What am I?\",\n        answer: \"Smoke\",\n        explanation: \"Smoke has no fixed form and expands to fill any space. You cannot hold it with your hands. It is a by-product of combustion — created by fire but distinct from it.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"elements\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"dust\",\n        slug: \"born-from-everything-settles-everywhere\",\n        question: \"I am born from everything yet I am nothing on my own. I settle on every surface you forget. I am the fate of all things eventually. What am I?\",\n        answer: \"Dust\",\n        explanation: \"Dust is composed of tiny particles from everything — skin, fabric, soil, pollen. It settles on neglected surfaces. In a grand sense, all matter eventually breaks down to dust.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"spider\",\n        slug: \"eight-legs-architect-without-tools\",\n        question: \"I have eight legs and I build with what comes from inside me. My home catches my meals. I am feared by many but harm few. What am I?\",\n        answer: \"A Spider\",\n        explanation: \"Spiders have eight legs and produce silk internally to spin webs. The web serves as both home and trap for prey. The vast majority of spider species are entirely harmless to humans.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"animals\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"bee\",\n        slug: \"gold-and-black-gives-sweetness-deadly-if-crossed\",\n        question: \"Dressed in gold and black, I give the world sweetness. I live and die for my queen. Cross me and I wound myself in the process. What am I?\",\n        answer: \"A Bee\",\n        explanation: \"Bees have distinctive yellow and black stripes. Worker bees produce honey devoted to their queen. When a honeybee stings, its barbed stinger lodges in the victim and tears free from the bee — killing it in the act.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"animals\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"butterfly\",\n        slug: \"born-one-form-dies-another\",\n        question: \"I am born in one form and die in a completely different one. I begin on the ground and end in the air. I am reborn without dying. What am I?\",\n        answer: \"A Butterfly\",\n        explanation: \"A butterfly begins as a caterpillar — a ground-dwelling creature. It forms a chrysalis and emerges transformed, able to fly. The metamorphosis is effectively a total biological reinvention.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"animals\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"snake\",\n        slug: \"no-legs-moves-faster-than-walking\",\n        question: \"I have no legs yet I can move faster than a walk. I shed my skin and am reborn. I am ancient and feared across every culture. What am I?\",\n        answer: \"A Snake\",\n        explanation: \"Snakes are legless yet can move at surprising speeds. They shed their skin periodically as they grow. Fear of snakes appears in almost every human culture and mythology.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"animals\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"fish\",\n        slug: \"live-in-water-die-in-air\",\n        question: \"I live in water and die in air. I breathe without lungs. I am silent yet my world is full of sound. What am I?\",\n        answer: \"A Fish\",\n        explanation: \"Fish live underwater and suffocate when removed from it. They breathe using gills rather than lungs. The underwater world is filled with sounds that fish both make and detect.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"animals\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"bird\",\n        slug: \"two-wings-two-legs-sings-without-instrument\",\n        question: \"Two wings, two legs, but I live between sky and earth. I build my home in branches. I sing though I have no instrument. What am I?\",\n        answer: \"A Bird\",\n        explanation: \"Birds have two wings and two legs. They nest in trees and other elevated places. Birdsong is produced by a specialised vocal organ called the syrinx.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"animals\",\n            \"nature\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"fence\",\n        slug: \"divides-without-cutting\",\n        question: \"I divide without cutting and connect without touching. I am always in between but I belong to neither side. What am I?\",\n        answer: \"A Fence\",\n        explanation: \"A fence divides two areas without physically cutting either. It marks a boundary and connects adjacent plots without physically touching either property. It belongs to the boundary, not one side or the other.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"structures\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"road\",\n        slug: \"millions-walk-on-me-never-move\",\n        question: \"Millions walk on me, drive on me, and run on me. I go everywhere but I never move. The more you use me the more worn I become. What am I?\",\n        answer: \"A Road\",\n        explanation: \"Roads carry enormous traffic daily yet remain stationary themselves. They connect distant places without moving. Over time, heavy use gradually wears down the surface.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"structures\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"window\",\n        slug: \"see-through-cannot-pass-without-breaking\",\n        question: \"You can see through me but you cannot walk through me without breaking me. I keep the cold out but let the light in. What am I?\",\n        answer: \"A Window\",\n        explanation: \"A glass window is transparent — you can see through it clearly. But it is a solid barrier you cannot pass through without shattering it. It insulates against cold while allowing natural light to enter.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"structures\",\n            \"objects\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"door\",\n        slug: \"opened-closed-thousands-times-never-complains\",\n        question: \"I stand all day. I am opened and closed thousands of times yet I never complain. I am your first welcome and last farewell. What am I?\",\n        answer: \"A Door\",\n        explanation: \"A door remains standing and is opened and closed repeatedly without complaint. It is the first thing that greets visitors arriving and the last thing encountered when leaving.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"structures\",\n            \"objects\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"horizon\",\n        slug: \"walk-towards-me-further-i-move-away\",\n        question: \"The more you walk towards me, the further I move away. You can always see me but you can never reach me. What am I?\",\n        answer: \"The Horizon\",\n        explanation: \"The horizon is the line where the earth meets the sky. As you move toward it, it always remains the same distance away because it is defined by your own viewpoint and the curvature of the Earth.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nature\",\n            \"abstract\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"grave\",\n        slug: \"dug-for-living-filled-by-dead\",\n        question: \"I am dug for the living yet filled by the dead. I cost everything but give nothing back. What am I?\",\n        answer: \"A Grave\",\n        explanation: \"A grave is dug in preparation for someone still alive — the dying or recently deceased. Once filled, the person buried there is gone forever. It takes a life but returns nothing.\",\n        category: \"classic\",\n        difficulty: \"hard\",\n        tags: [\n            \"dark\",\n            \"classic\",\n            \"life\"\n        ]\n    },\n    {\n        id: \"promise\",\n        slug: \"keep-or-break-made-or-lost\",\n        question: \"I can be kept or broken. I can be made or lost. I am not a physical thing, yet I carry enormous weight. What am I?\",\n        answer: \"A Promise\",\n        explanation: \"Promises are kept or broken, made or lost — all figures of speech for something entirely intangible. Yet a broken promise can carry devastating real-world consequences.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"emotions\"\n        ]\n    },\n    {\n        id: \"dream\",\n        slug: \"come-when-eyes-closed-vanish-when-open\",\n        question: \"I come when you close your eyes and vanish when you open them. I can terrify or delight you. I feel real yet I never am. What am I?\",\n        answer: \"A Dream\",\n        explanation: \"Dreams occur during sleep — when eyes are closed — and dissolve upon waking. Nightmares terrify; beautiful dreams delight. They feel completely vivid and real yet exist only in the mind.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"abstract\",\n            \"sleep\",\n            \"mind\"\n        ]\n    },\n    {\n        id: \"memory\",\n        slug: \"crystal-clear-or-impossibly-blurry\",\n        question: \"I can be crystal clear or impossibly blurry. I comfort you or haunt you. I am not real, yet I shape who you are. What am I?\",\n        answer: \"A Memory\",\n        explanation: \"Some memories are vivid; others fade. Joyful memories comfort us; painful ones can haunt us. Memories are not physical things but they fundamentally shape our personality and decisions.\",\n        category: \"classic\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"mind\",\n            \"philosophy\"\n        ]\n    },\n    {\n        id: \"time-classic\",\n        slug: \"everyone-has-it-nobody-can-stop-it\",\n        question: \"Everyone has it. Nobody can give it away. Nobody can stop it. The more of it you use, the less you have. What is it?\",\n        answer: \"Time\",\n        explanation: \"Every person has time, but you cannot give your time to someone else in a literal sense. Nothing stops the passage of time. And every second spent is a second you will never get back.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"time\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"name\",\n        slug: \"given-at-birth-never-called-yourself\",\n        question: \"Everyone has me and uses me every day. You were given me at birth. Others call you by me, but you never call yourself by me. What am I?\",\n        answer: \"Your Name\",\n        explanation: \"Your name is intangible — you cannot hold it. You received it at birth. Others use it constantly to address you, but when you think of yourself internally, you rarely say your own name.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"identity\"\n        ]\n    },\n    {\n        id: \"birthday\",\n        slug: \"more-you-have-older-you-are\",\n        question: \"The more of these you have, the older you are. Yet many people wish for more of them. They come once a year and are celebrated with candles. What are they?\",\n        answer: \"Birthdays\",\n        explanation: \"Each birthday marks another year of life — the more you have accumulated the older you are. Yet most people happily celebrate and wish for many more birthdays, even as they age.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"time\",\n            \"life\"\n        ]\n    },\n    {\n        id: \"sleeping\",\n        slug: \"everyone-does-it-few-remember-it\",\n        question: \"Everyone does it but few remember it. You spend a third of your life doing it. It restores you, heals you, and is ruined by babies. What is it?\",\n        answer: \"Sleeping\",\n        explanation: \"Humans spend roughly a third of their lives asleep. Dreams occur during sleep but are usually forgotten. Sleep is essential for physical and mental restoration. And new parents universally lose large amounts of it.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"life\",\n            \"body\"\n        ]\n    },\n    {\n        id: \"homework\",\n        slug: \"children-dread-teachers-love\",\n        question: \"Children dread me, teachers love me, parents nag about me. I follow you home but I am not a pet. What am I?\",\n        answer: \"Homework\",\n        explanation: \"Homework is universally dreaded by students, assigned by teachers, and a source of constant nagging by parents. It follows students home from school just like a loyal but unwanted companion.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"school\",\n            \"life\"\n        ]\n    },\n    {\n        id: \"ruler\",\n        slug: \"rules-without-power-measures-without-thinking\",\n        question: \"I rule without power, measure without thinking, and am used in school but rarely at weekends. What am I?\",\n        answer: \"A Ruler\",\n        explanation: \"A ruler is called a ruler but has no actual authority. It measures length without any intelligence of its own. It is primarily a school tool — rarely needed outside of education.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"school\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"pencil\",\n        slug: \"makes-marks-can-be-undone\",\n        question: \"I make my mark but can always be undone. I am sharp at first and blunt with use. I am older than the pen. What am I?\",\n        answer: \"A Pencil\",\n        explanation: \"Pencil marks can be erased — unlike ink. A pencil starts sharp and becomes blunt as the graphite wears down. The pencil predates the modern ballpoint pen by several centuries.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"school\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"scissors\",\n        slug: \"two-blades-useless-alone\",\n        question: \"Two of us together and I am powerful. Separate us and I am useless. I am sharp but I am for creation not destruction. What am I?\",\n        answer: \"Scissors\",\n        explanation: \"Scissors have two blades that only work when hinged together — a single blade alone cannot cut properly. Despite being sharp, scissors are primarily creative tools.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"objects\",\n            \"school\"\n        ]\n    },\n    {\n        id: \"football\",\n        slug: \"no-legs-runs-across-fields\",\n        question: \"I have no legs yet I run across fields. I am round yet I never travel in a straight line when kicked. I bring people together in their millions. What am I?\",\n        answer: \"A Football\",\n        explanation: \"A football rolls and travels across pitches without legs. Its round shape and the way it is kicked means it rarely travels in a perfect straight line. Football is the world's most popular sport.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"sport\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"bicycle\",\n        slug: \"two-wheels-no-engine-rider-powers-it\",\n        question: \"Two wheels but no engine. I go where no car can follow. I am powered by the very person I carry. What am I?\",\n        answer: \"A Bicycle\",\n        explanation: \"A bicycle has two wheels and requires no engine — it is powered purely by the rider pedalling. Its narrow profile allows it to navigate paths inaccessible to cars.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"transport\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"glasses\",\n        slug: \"help-see-clearly-forget-they-are-there\",\n        question: \"I help you see more clearly yet many people forget I am even there. I sit on your face but you look through me not at me. Without me the world is a blur. What am I?\",\n        answer: \"Glasses\",\n        explanation: \"Eyeglasses correct vision defects and are worn so constantly that people often forget they are there. The wearer looks through the lenses rather than at them.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"objects\",\n            \"health\"\n        ]\n    },\n    {\n        id: \"hat\",\n        slug: \"crown-for-common-person\",\n        question: \"I am a crown for those without a kingdom. I shelter you from sun and rain. Take me off to show respect. What am I?\",\n        answer: \"A Hat\",\n        explanation: \"A hat sits on the head like a crown but without royalty. It provides shade from the sun and shelter from rain. The tradition of removing a hat as a sign of respect dates back centuries.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"clothing\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"kite\",\n        slug: \"flies-but-always-tied-down\",\n        question: \"I fly but I am always tied down. I need the wind and a willing hand. Let go of me and I am lost. What am I?\",\n        answer: \"A Kite\",\n        explanation: \"A kite soars in the air but is always connected to its flier by a string. It needs wind to stay aloft and someone actively holding the string. Release the string and it flies away and is lost.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"toys\",\n            \"nature\"\n        ]\n    },\n    {\n        id: \"balloon\",\n        slug: \"full-of-nothing-brings-joy\",\n        question: \"I am full of nothing yet I bring joy to children everywhere. Pop me and I am gone in an instant. I rise when released. What am I?\",\n        answer: \"A Balloon\",\n        explanation: \"A balloon is filled with air or helium. It brings joy at parties. A pin pop destroys it instantly. Helium balloons float upward when released and eventually disappear from sight.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"toys\",\n            \"celebrations\"\n        ]\n    },\n    {\n        id: \"photograph\",\n        slug: \"freezes-moment-forever-never-alive\",\n        question: \"I freeze a moment forever but I am never alive. I show you people who may be long gone. I fade over decades but I never forget. What am I?\",\n        answer: \"A Photograph\",\n        explanation: \"A photograph captures a single instant in time permanently. It can show people long since dead. Physical photographs fade over decades from light and age — yet the moment they captured lives on in them.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"objects\",\n            \"art\"\n        ]\n    },\n    {\n        id: \"calendar\",\n        slug: \"twelve-rooms-three-hundred-sixty-five-floors\",\n        question: \"I have twelve rooms and three hundred and sixty five floors. Each floor is used only once and then discarded. What am I?\",\n        answer: \"A Calendar\",\n        explanation: \"A calendar has twelve months — the twelve rooms. It has 365 days — the floors. Each day passes and is gone. At the end of the year the whole thing is thrown away and replaced.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"classic\",\n            \"time\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"thermometer\",\n        slug: \"measures-hot-cold-never-feels\",\n        question: \"I measure how hot and cold the world is but I never feel it myself. I rise when others suffer and fall when they are relieved. What am I?\",\n        answer: \"A Thermometer\",\n        explanation: \"A thermometer measures temperature precisely but has no sensation of its own. Mercury or digital indicators rise with heat and fall as things cool down.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"science\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"hourglass\",\n        slug: \"sand-marks-time-flip-to-begin-again\",\n        question: \"I measure time with sand. When I run out, flip me over and I begin again. I am ancient yet as accurate as I ever was. What am I?\",\n        answer: \"An Hourglass\",\n        explanation: \"An hourglass measures a fixed period of time as sand flows from the top chamber to the bottom. When empty, it is turned upside down and starts again. Hourglasses have been used for thousands of years.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"time\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"canoe\",\n        slug: \"ribs-but-no-bones-moves-with-arms\",\n        question: \"I have ribs but no bones. I move through water using human arms. I carry one or two but never more. What am I?\",\n        answer: \"A Canoe\",\n        explanation: \"A canoe has structural ribs along its hull — no actual bones. It is propelled by paddling and typically carries one or two people. A classic water riddle.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"nautical\",\n            \"classic\",\n            \"sport\"\n        ]\n    },\n    {\n        id: \"lighthouse\",\n        slug: \"stands-in-the-sea-never-swims\",\n        question: \"I stand in the sea but never swim. I shine all night but give no warmth. I warn those far away from something near. What am I?\",\n        answer: \"A Lighthouse\",\n        explanation: \"A lighthouse stands on rocks or the shore surrounded by water but never moves. Its light shines through the night but is a cold beam, not a heat source. It warns sailors of dangerous rocks nearby.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"nautical\",\n            \"classic\",\n            \"structures\"\n        ]\n    },\n    {\n        id: \"magnet\",\n        slug: \"attracts-some-repels-others\",\n        question: \"I attract some things and repel others. I am strongest at my ends. I have an invisible force yet I am made of metal. What am I?\",\n        answer: \"A Magnet\",\n        explanation: \"A magnet attracts iron and steel but repels other magnets of the same pole. Its force is strongest at the north and south poles. The magnetic field is completely invisible yet powerfully real.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"science\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"scales\",\n        slug: \"i-weigh-things-without-opinion\",\n        question: \"I weigh everything without opinion. I am the symbol of justice and the tool of the trader. I have two sides but I always seek balance. What am I?\",\n        answer: \"A Pair of Scales\",\n        explanation: \"Scales measure weight objectively — with no bias or opinion. The scales of justice are the symbol of law and fairness. A balance scale has two pans and achieves equilibrium when both sides are equal.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"classic\",\n            \"science\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"telescope\",\n        slug: \"makes-far-things-near\",\n        question: \"I make the far seem near and the invisible seem real. I brought humans to the stars without leaving the ground. What am I?\",\n        answer: \"A Telescope\",\n        explanation: \"A telescope uses lenses or mirrors to magnify distant objects, making far-off stars and planets visible. It has transformed our understanding of the universe without anyone physically travelling there.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"science\",\n            \"space\"\n        ]\n    },\n    {\n        id: \"microscope\",\n        slug: \"makes-invisible-visible\",\n        question: \"I make the invisible visible. I revealed a world hiding beneath your feet, in your water, and on your skin. What am I?\",\n        answer: \"A Microscope\",\n        explanation: \"A microscope magnifies objects too small for the naked eye — revealing bacteria, cells, and microorganisms that were entirely unknown before its invention. It transformed medicine and biology.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"science\"\n        ]\n    },\n    {\n        id: \"battery2\",\n        slug: \"stores-power-releases-slowly\",\n        question: \"I store power but I am powerless on my own. I make devices come alive. Leave me unused for too long and I slowly die. What am I?\",\n        answer: \"A Battery\",\n        explanation: \"A battery stores chemical energy and converts it to electrical energy on demand. Without a connected device it does nothing. Batteries discharge slowly even when not in use, eventually running flat.\",\n        category: \"classic\",\n        difficulty: \"easy\",\n        tags: [\n            \"classic\",\n            \"science\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"clock3\",\n        slug: \"ticks-all-day-no-heartbeat\",\n        question: \"I tick all day and night yet I have no heartbeat. I am precise but I am always slightly wrong. Every hundred years I need to be corrected. What am I?\",\n        answer: \"A Clock\",\n        explanation: \"A mechanical clock ticks continuously — the sound of the escapement mechanism — with no living heartbeat. Even the most precise clocks drift fractionally over time. Atomic clocks require periodic corrections to stay aligned with Earth's rotation.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"classic\",\n            \"time\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"soap\",\n        slug: \"i-clean-by-getting-dirty\",\n        question: \"I clean by getting dirty myself. I disappear as I do my job. I make the invisible visible in bubbles. What am I?\",\n        answer: \"Soap\",\n        explanation: \"Soap works by binding to dirt and oil on the skin and carrying it away in water — in doing so it becomes dirty itself. A bar of soap diminishes with use. The bubbles it creates are a visible side effect of its cleaning action.\",\n        category: \"classic\",\n        difficulty: \"medium\",\n        tags: [\n            \"classic\",\n            \"objects\",\n            \"hygiene\"\n        ]\n    },\n    {\n        id: \"mirror3\",\n        slug: \"shows-past-version-of-yourself\",\n        question: \"I show you a version of yourself from a tiny fraction of a second in the past. The image you see is never truly you right now. What am I?\",\n        answer: \"A Mirror\",\n        explanation: \"Light takes a tiny but real amount of time to travel from you to the mirror and back to your eyes. So the reflection you see is technically from the past — however infinitesimally small that gap is. A beautifully precise riddle.\",\n        category: \"classic\",\n        difficulty: \"hard\",\n        tags: [\n            \"classic\",\n            \"science\",\n            \"objects\",\n            \"physics\"\n        ]\n    },\n    // ═══════════════════════════════════════════\n    // WORDPLAY\n    // ═══════════════════════════════════════════\n    {\n        id: \"letter-m\",\n        slug: \"once-in-minute-twice-in-moment\",\n        question: \"I come once in a minute, twice in a moment, but never in a thousand years. What am I?\",\n        answer: \"The Letter M\",\n        explanation: \"Look at the words: minute contains one M, moment contains two M's, and a thousand years contains no M at all.\",\n        category: \"wordplay\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"letters\"\n        ]\n    },\n    {\n        id: \"joke\",\n        slug: \"cracked-made-told-played\",\n        question: \"I can be cracked, made, told, and played. What am I?\",\n        answer: \"A Joke\",\n        explanation: \"You crack a joke, make a joke, tell a joke, and play a joke on someone. All four verbs work perfectly with the single word — a delightful piece of wordplay.\",\n        category: \"wordplay\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"zip\",\n        slug: \"teeth-cannot-bite-zip\",\n        question: \"I have teeth but I cannot bite. I help things come together. Pull me apart and things fall apart too. What am I?\",\n        answer: \"A Zip\",\n        explanation: \"A zipper has rows of interlocking teeth that join two sides of fabric together. They cannot bite anything. Pull the zip apart and the two sides separate.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"wordplay\"\n        ]\n    },\n    {\n        id: \"stamp\",\n        slug: \"travels-world-without-moving\",\n        question: \"I travel the world and never move. I have a face but no body. I am small but I carry great stories. What am I?\",\n        answer: \"A Postage Stamp\",\n        explanation: \"A stamp travels with the letter it is stuck to, visiting countries and cities — without moving on its own. It has a printed image and enables written stories to journey far.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"travel\"\n        ]\n    },\n    {\n        id: \"secret\",\n        slug: \"everyone-wants-to-tell-less-you-are\",\n        question: \"Everyone wants to tell me but wishes they hadn't. The more people know me, the less I am. What am I?\",\n        answer: \"A Secret\",\n        explanation: \"People often feel compelled to share secrets then regret it. The more people who know a secret, the less secret it becomes — until everyone knows and it ceases to exist.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"wordplay\",\n            \"social\"\n        ]\n    },\n    {\n        id: \"cold-illness\",\n        slug: \"everyone-hopes-avoid-everyone-catches\",\n        question: \"Everyone hopes to avoid me yet everyone catches me eventually. I spread easily in winter and hide in summer. What am I?\",\n        answer: \"A Cold\",\n        explanation: \"A common cold is something everyone tries to avoid but catches nonetheless. It spreads more readily in cold weather and is most dangerous for children and the elderly.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"health\"\n        ]\n    },\n    {\n        id: \"bank\",\n        slug: \"money-branches-interest-not-tree\",\n        question: \"I hold your money but I am not a wallet. I have branches but I am not a tree. I have interest but I am not a hobby. What am I?\",\n        answer: \"A Bank\",\n        explanation: \"A bank holds money, has branch offices, and charges or pays interest — but none of these uses are the everyday meanings of those words. Three wordplay clues in one.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"money\"\n        ]\n    },\n    {\n        id: \"court\",\n        slug: \"kings-play-criminals-stand-served-here\",\n        question: \"Kings play here and criminals stand here. It seeks fairness in one place and tests your serve in another. What am I?\",\n        answer: \"A Court\",\n        explanation: \"A court can be a sports court, a law court seeking justice, or a food court where food is served. Multiple meanings of one word layered into one riddle.\",\n        category: \"wordplay\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"light\",\n        slug: \"opposite-heavy-opposite-dark\",\n        question: \"I am the opposite of heavy and also the opposite of dark. I fill a room instantly. I travel faster than anything in the universe. What am I?\",\n        answer: \"Light\",\n        explanation: \"Light means both not heavy and not dark — a double meaning in English. Light fills a room the instant a switch is flicked. The speed of light is the ultimate speed limit of the universe.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"physics\",\n            \"nature\"\n        ]\n    },\n    {\n        id: \"date\",\n        slug: \"on-calendar-on-tree-romantic-evening\",\n        question: \"I hang on a tree, appear on a calendar, and describe a romantic evening. What am I?\",\n        answer: \"A Date\",\n        explanation: \"Dates are a fruit that grow in clusters on date palms. A date is also a specific day on a calendar. And going on a date is a romantic outing. Three completely different meanings, one word.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"pitch\",\n        slug: \"football-field-music-note-black-tar\",\n        question: \"Football is played on me. Music has me. I am also the darkest substance used on rooftops. What am I?\",\n        answer: \"Pitch\",\n        explanation: \"A football pitch is the playing field. Musical pitch is the frequency of a note. Pitch is also a black tar-like substance used in waterproofing. Three meanings of one word.\",\n        category: \"wordplay\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"spring\",\n        slug: \"season-water-coil-leap\",\n        question: \"I am a season, a source of water, a coil of metal, and a verb meaning to leap. What am I?\",\n        answer: \"Spring\",\n        explanation: \"Spring is the season after winter. A spring is a natural water source. A spring is a coiled mechanical component. And to spring means to jump. Four meanings, one word.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"watch\",\n        slug: \"worn-wrist-watch-film-sailors-duty\",\n        question: \"You wear me on your wrist, you also do me at a film, and a sailor does me through the night. What am I?\",\n        answer: \"A Watch\",\n        explanation: \"A watch is a wrist-worn timepiece. To watch a film means to observe it. And a watch is a sailor's shift of duty through the night. Three meanings of the same word.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"objects\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"leaves\",\n        slug: \"tree-has-book-has-person-does\",\n        question: \"A tree has them, a book has them, and a person does it. What are they?\",\n        answer: \"Leaves\",\n        explanation: \"A tree has leaves. A book has leaves — an old word for pages. And a person leaves — as in departs. Three uses of the same word.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"pen\",\n        slug: \"writer-farmer-prisoner\",\n        question: \"A writer uses me, a farmer uses me, and a prisoner lives in me. What am I?\",\n        answer: \"A Pen\",\n        explanation: \"A pen is what a writer uses to write. A pen is an enclosure for animals on a farm. And a pen — short for penitentiary — is where a prisoner lives.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"objects\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"bark\",\n        slug: \"dog-does-it-tree-has-it-boat-does-it\",\n        question: \"A dog does it, a tree has it, and a ship does it in a harbour. What is it?\",\n        answer: \"Bark\",\n        explanation: \"A dog barks. A tree has bark — the outer layer of its trunk. And a bark is an old word for a sailing vessel — it barks (moors) in a harbour. Three meanings.\",\n        category: \"wordplay\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"language\",\n            \"animals\"\n        ]\n    },\n    {\n        id: \"glasses2\",\n        slug: \"drinking-or-seeing\",\n        question: \"Without me you cannot see clearly. Without me you cannot drink elegantly. One of me sits on your nose, the other on your table. What am I?\",\n        answer: \"Glasses\",\n        explanation: \"Glasses are spectacles worn on the nose to correct vision. Glasses are also drinking vessels. Two entirely different objects sharing one word.\",\n        category: \"wordplay\",\n        difficulty: \"easy\",\n        tags: [\n            \"wordplay\",\n            \"objects\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"ring\",\n        slug: \"finger-phone-boxing-circus\",\n        question: \"I go on your finger, I summon you to answer, I surround a boxing match, and a circus performs in me. What am I?\",\n        answer: \"A Ring\",\n        explanation: \"A ring is jewellery for the finger. A phone rings to summon you. A boxing ring is the square arena. And a circus ring is the circular performance area. Four meanings, one word.\",\n        category: \"wordplay\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"pound\",\n        slug: \"weight-money-hit-dog-home\",\n        question: \"I measure weight, I am British money, I am what you do to a nail, and I am where lost dogs go. What am I?\",\n        answer: \"A Pound\",\n        explanation: \"A pound is a unit of weight. A pound is British currency. To pound means to hit hard. And a dog pound is where stray dogs are held. Four meanings of the same word.\",\n        category: \"wordplay\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    // ═══════════════════════════════════════════\n    // LATERAL THINKING\n    // ═══════════════════════════════════════════\n    {\n        id: \"map\",\n        slug: \"cities-no-houses-mountains-no-trees\",\n        question: \"I have cities but no houses live there. I have mountains but no trees grow. I have water but no fish swim. I have roads but no cars drive. What am I?\",\n        answer: \"A Map\",\n        explanation: \"A map represents the world symbolically. It depicts cities, mountains, rivers and roads — but only as markings. Nothing in a map physically exists within it.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"objects\",\n            \"geography\"\n        ]\n    },\n    {\n        id: \"dictionary\",\n        slug: \"tomorrow-before-yesterday\",\n        question: \"When does tomorrow come before yesterday?\",\n        answer: \"In a dictionary\",\n        explanation: \"In alphabetical order, T comes before Y. So the word tomorrow comes before the word yesterday when arranged alphabetically in a dictionary.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"wordplay\",\n            \"lateral\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"rainbow-w\",\n        slug: \"what-at-end-of-rainbow\",\n        question: \"What is at the end of a rainbow?\",\n        answer: \"The letter W\",\n        explanation: \"Look at the word rainbow. At the end of the word rainbow is the letter W. A classic trick riddle that plays on the difference between a word and the concept it represents.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"wordplay\",\n            \"lateral\"\n        ]\n    },\n    {\n        id: \"mirror-lateral\",\n        slug: \"left-is-right-right-is-left\",\n        question: \"I make your left hand your right hand and your right hand your left. I show you yourself but not as others see you. What am I?\",\n        answer: \"A Mirror\",\n        explanation: \"A mirror flips your image horizontally. It shows you yourself, but the reversed image is not what others see when they look at you.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"objects\",\n            \"lateral\",\n            \"perception\"\n        ]\n    },\n    {\n        id: \"circle\",\n        slug: \"no-beginning-middle-end\",\n        question: \"What has no beginning, no middle, and no end?\",\n        answer: \"A Circle\",\n        explanation: \"A circle is a continuous loop — you can trace it forever without ever finding a start, a middle, or an end. It is the only simple shape with this property.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"lateral\",\n            \"shapes\",\n            \"abstract\"\n        ]\n    },\n    {\n        id: \"towel\",\n        slug: \"wetter-as-it-dries\",\n        question: \"The more it dries, the wetter it becomes. What is it?\",\n        answer: \"A Towel\",\n        explanation: \"A towel becomes wetter as it dries things — it absorbs water from whatever it is drying. The drier the object it dries, the wetter the towel becomes.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"lateral\",\n            \"objects\"\n        ]\n    },\n    {\n        id: \"blackboard\",\n        slug: \"white-when-dirty-black-when-clean\",\n        question: \"I am white when dirty and black when clean. What am I?\",\n        answer: \"A Blackboard\",\n        explanation: \"A blackboard is black when clean and empty. When used — considered dirty — it is covered in white chalk marks. The riddle reverses normal expectations.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"lateral\",\n            \"objects\",\n            \"school\"\n        ]\n    },\n    {\n        id: \"wrong-spelling\",\n        slug: \"spell-wrong-correctly\",\n        question: \"A teacher asks a student to spell wrong. The student spells W-R-O-N-G. Was the student right or wrong?\",\n        answer: \"Right — they spelled wrong correctly\",\n        explanation: \"The teacher said spell wrong. W-R-O-N-G is the correct spelling of the word wrong. The student was right. The riddle tricks you into thinking wrong means incorrectly.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"lateral\",\n            \"wordplay\",\n            \"language\"\n        ]\n    },\n    {\n        id: \"twelve-months\",\n        slug: \"how-many-months-28-days\",\n        question: \"How many months have 28 days?\",\n        answer: \"All twelve\",\n        explanation: \"Every single month has at least 28 days. The trick is that the question implies only February has 28 days — but every month contains the 28th of the month.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"lateral\",\n            \"time\",\n            \"maths\"\n        ]\n    },\n    {\n        id: \"shadow-running\",\n        slug: \"faster-you-run-harder-to-catch\",\n        question: \"The faster you run, the harder I am to catch. Yet I am always the same distance ahead of you. What am I?\",\n        answer: \"Your shadow (when running away from the sun)\",\n        explanation: \"When you run away from the sun, your shadow stretches ahead of you. No matter how fast you run, it always moves at exactly the same speed — always just as far in front.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"lateral\",\n            \"nature\",\n            \"abstract\"\n        ]\n    },\n    {\n        id: \"half-of-eight\",\n        slug: \"what-is-half-of-eight\",\n        question: \"What is half of 8? There are two correct answers.\",\n        answer: \"4 — or 0 (if you fold the digit 8 horizontally, both halves are 0)\",\n        explanation: \"Half of eight is four mathematically. But if you draw the number 8 and fold it horizontally across the middle, both the top and bottom halves look like 0. Two correct interpretations of the same question.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"lateral\",\n            \"maths\",\n            \"wordplay\"\n        ]\n    },\n    {\n        id: \"throw-away-to-use\",\n        slug: \"throw-me-away-to-use-me\",\n        question: \"You must throw me away to use me. You only use me once. I am essential on birthdays. What am I?\",\n        answer: \"A Blown-out Candle\",\n        explanation: \"A birthday candle must be blown out — in effect thrown away — to be used correctly and make a wish. The act of use is the act of ending.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"lateral\",\n            \"objects\",\n            \"celebrations\"\n        ]\n    },\n    {\n        id: \"floor-ceiling\",\n        slug: \"what-does-ceiling-have-floor-does-not\",\n        question: \"What does a ceiling have that a floor does not?\",\n        answer: \"The letter C\",\n        explanation: \"Look at the two words: ceiling begins with the letter C. Floor does not contain a C. A simple lateral wordplay trap.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"lateral\",\n            \"wordplay\",\n            \"letters\"\n        ]\n    },\n    {\n        id: \"ship-captain\",\n        slug: \"captain-of-ship-how-many-fish\",\n        question: \"If a ship captain has 15 fish and the sea is full of sharks, how many fish does he have?\",\n        answer: \"15 — the fish are already on the ship\",\n        explanation: \"The riddle implies the sharks will eat the fish, but the fish are on the ship — not in the sea. The captain still has all 15. A classic misdirection riddle.\",\n        category: \"lateral\",\n        difficulty: \"medium\",\n        tags: [\n            \"lateral\",\n            \"logic\"\n        ]\n    },\n    {\n        id: \"north-pole-bear\",\n        slug: \"bear-from-north-pole\",\n        question: \"A bear walks one mile south, one mile east, then one mile north and ends up exactly where it started. What colour is the bear?\",\n        answer: \"White — it is a polar bear at the North Pole\",\n        explanation: \"The only place on Earth where you can walk one mile south, one mile east, and one mile north and end up in your exact starting position is the North Pole. The only bear native to the North Pole is the polar bear, which is white.\",\n        category: \"lateral\",\n        difficulty: \"hard\",\n        tags: [\n            \"lateral\",\n            \"logic\",\n            \"animals\",\n            \"geography\"\n        ]\n    },\n    // ═══════════════════════════════════════════\n    // ABSTRACT\n    // ═══════════════════════════════════════════\n    {\n        id: \"time-abstract\",\n        slug: \"always-coming-never-arrives\",\n        question: \"I am always coming but never arrive. I am always passing but never gone. Everyone wants more of me but no one can hold me. What am I?\",\n        answer: \"Time\",\n        explanation: \"The future is always approaching but by the time it arrives it becomes the present and then the past. Time flows constantly yet we cannot grasp or contain it.\",\n        category: \"abstract\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"time\",\n            \"philosophy\"\n        ]\n    },\n    {\n        id: \"music\",\n        slug: \"travels-air-no-wings-understood-everywhere\",\n        question: \"I travel on air but have no wings. I can make you cry or dance. I have no language yet I am understood everywhere. What am I?\",\n        answer: \"Music\",\n        explanation: \"Sound waves carry music through the air. Music evokes deep emotions — joy, sadness, nostalgia. It transcends language and is felt and understood across every culture on earth.\",\n        category: \"abstract\",\n        difficulty: \"medium\",\n        tags: [\n            \"art\",\n            \"abstract\",\n            \"emotions\"\n        ]\n    },\n    {\n        id: \"grief\",\n        slug: \"price-you-pay-for-love\",\n        question: \"I am the price you pay for love. The greater the love, the heavier I am. I am not an illness yet I can break the strongest person. What am I?\",\n        answer: \"Grief\",\n        explanation: \"Grief is experienced in proportion to the love felt for what was lost. It is not a disease but it can be utterly debilitating. It is the emotional cost of having loved deeply.\",\n        category: \"abstract\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"emotions\",\n            \"philosophy\"\n        ]\n    },\n    {\n        id: \"hope\",\n        slug: \"feeds-no-one-sustains-millions\",\n        question: \"I feed no one yet I have sustained millions through famine. I cure nothing yet the sick hold onto me. I cost nothing yet I am priceless. What am I?\",\n        answer: \"Hope\",\n        explanation: \"Hope provides no food or medicine yet it has kept people alive through the worst conditions imaginable. It is freely available to anyone yet its value to the human spirit is immeasurable.\",\n        category: \"abstract\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"emotions\",\n            \"philosophy\"\n        ]\n    },\n    {\n        id: \"courage\",\n        slug: \"not-absence-of-fear-decision-to-act\",\n        question: \"I am not the absence of fear but the decision to act despite it. Animals have instinct, but only people truly have me. What am I?\",\n        answer: \"Courage\",\n        explanation: \"Courage is not fearlessness — it is taking action in the face of fear. Animals act on instinct for survival, but the conscious choice to be brave in full knowledge of the risk is uniquely human.\",\n        category: \"abstract\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"philosophy\",\n            \"emotions\"\n        ]\n    },\n    {\n        id: \"truth\",\n        slug: \"some-refuse-to-see-me\",\n        question: \"Some refuse to see me even when I am directly in front of them. I hurt at first but heal in the long run. I am the same for everyone, even when people disagree. What am I?\",\n        answer: \"The Truth\",\n        explanation: \"People often deny the truth even when presented with clear evidence. The truth can be painful in the moment but leads to better outcomes. It is objective and does not change based on opinion.\",\n        category: \"abstract\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"philosophy\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"lie\",\n        slug: \"born-in-instant-lives-forever\",\n        question: \"I am born in an instant and can live forever. I never breathe yet I spread faster than disease. One of me can destroy a lifetime's reputation. What am I?\",\n        answer: \"A Lie\",\n        explanation: \"A lie is created in a moment but its consequences can last indefinitely. Lies spread with extraordinary speed. A single lie can undo a lifetime of honest reputation.\",\n        category: \"abstract\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"philosophy\",\n            \"social\"\n        ]\n    },\n    {\n        id: \"laughter\",\n        slug: \"contagious-not-illness-best-medicine\",\n        question: \"I am contagious but I am not an illness. I am free yet I am said to be the best medicine. I escape at the worst possible moments. What am I?\",\n        answer: \"Laughter\",\n        explanation: \"Laughter spreads from person to person involuntarily — it is genuinely contagious. It has proven health benefits. And it often erupts at the most inappropriate moments.\",\n        category: \"abstract\",\n        difficulty: \"easy\",\n        tags: [\n            \"abstract\",\n            \"emotions\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"silence-abstract\",\n        slug: \"loudest-thing-in-empty-room\",\n        question: \"I am the loudest thing in an empty room. I am what you hear when all sound is gone. I am uncomfortable for many yet peaceful for few. What am I?\",\n        answer: \"Silence\",\n        explanation: \"When there is no sound, silence becomes almost physically present — especially in an empty room. Many people find silence uncomfortable and fill it with noise. Others find it deeply peaceful.\",\n        category: \"abstract\",\n        difficulty: \"medium\",\n        tags: [\n            \"abstract\",\n            \"sound\",\n            \"classic\"\n        ]\n    },\n    {\n        id: \"thought\",\n        slug: \"no-weight-can-crush-no-arms-can-embrace\",\n        question: \"I have no weight yet I can crush you. I have no arms yet I can embrace you. I live in your mind but affect your whole body. What am I?\",\n        answer: \"A Thought\",\n        explanation: \"Thoughts are weightless and invisible, yet a single thought can cause overwhelming anxiety or beautiful joy — physically affecting heart rate, breathing, and more.\",\n        category: \"abstract\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"mind\",\n            \"philosophy\"\n        ]\n    },\n    {\n        id: \"colour\",\n        slug: \"no-colour-myself-without-me-no-colour\",\n        question: \"I exist all around you but I have no colour of my own. Without me you would see no colour at all. I am destroyed by darkness yet I create it. What am I?\",\n        answer: \"Light\",\n        explanation: \"Light itself has no colour — it is a spectrum of wavelengths that the eye interprets as colour. Without light there would be no colour perception. Light is extinguished by darkness, yet the absence of light is what creates darkness.\",\n        category: \"abstract\",\n        difficulty: \"hard\",\n        tags: [\n            \"abstract\",\n            \"physics\",\n            \"nature\"\n        ]\n    },\n    // ═══════════════════════════════════════════\n    // MODERN\n    // ═══════════════════════════════════════════\n    {\n        id: \"search-engine\",\n        slug: \"ask-me-anything-i-know-everything\",\n        question: \"Ask me anything and I will answer — but I have no mind. I know everything ever written, yet I understand nothing. What am I?\",\n        answer: \"A Search Engine\",\n        explanation: \"A search engine can retrieve any piece of published text in seconds. It appears to know everything. Yet it has no understanding — only pattern-matching against an enormous index.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\"\n        ]\n    },\n    {\n        id: \"smartphone\",\n        slug: \"camera-phone-computer-map-clock-library\",\n        question: \"I am a camera, a phone, a computer, a map, a clock, and a library — all in your pocket. Thirty years ago I did not exist. Today people panic without me. What am I?\",\n        answer: \"A Smartphone\",\n        explanation: \"The smartphone combines dozens of previously separate devices into one. It was invented in the mid-1990s and became dominant in the 2000s and 2010s. People experience genuine anxiety when separated from their phones.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\"\n        ]\n    },\n    {\n        id: \"wifi\",\n        slug: \"invisible-carries-voices-films-music\",\n        question: \"I am invisible yet I surround you in your home. I carry voices, films, and music yet I make no sound. Switch me off and the whole house complains. What am I?\",\n        answer: \"Wi-Fi\",\n        explanation: \"Wi-Fi transmits data wirelessly using radio waves — completely invisible. It carries enormous amounts of audio and video data. Losing the Wi-Fi signal is a source of genuine frustration in modern households.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\"\n        ]\n    },\n    {\n        id: \"battery-modern\",\n        slug: \"everyone-checks-me-anxiously\",\n        question: \"Everyone checks on me with anxiety when I run low. I power your world silently. When I die, everything around me dies too. What am I?\",\n        answer: \"A Phone Battery\",\n        explanation: \"Phone battery anxiety is a documented modern phenomenon. Batteries power devices silently and invisibly. When a battery dies, every device it powers becomes useless.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\"\n        ]\n    },\n    {\n        id: \"cloud-storage\",\n        slug: \"stored-nowhere-accessible-everywhere\",\n        question: \"I store things in a place that has no address you can visit. I exist everywhere and nowhere. Lose your device but never lose me. What am I?\",\n        answer: \"Cloud Storage\",\n        explanation: \"Cloud storage holds data on remote servers in data centres around the world — no single physical location you can visit. Even if you lose your phone, your data in the cloud survives.\",\n        category: \"modern\",\n        difficulty: \"medium\",\n        tags: [\n            \"technology\",\n            \"modern\"\n        ]\n    },\n    {\n        id: \"algorithm\",\n        slug: \"decides-what-you-see-without-asking\",\n        question: \"I decide what you see without asking. I know your preferences better than you do. I am invisible yet I shape your opinions. What am I?\",\n        answer: \"An Algorithm\",\n        explanation: \"Social media and search algorithms curate what content you see based on your past behaviour. They can predict preferences with startling accuracy. They are entirely invisible yet profoundly shape what information you encounter.\",\n        category: \"modern\",\n        difficulty: \"hard\",\n        tags: [\n            \"technology\",\n            \"modern\",\n            \"abstract\"\n        ]\n    },\n    {\n        id: \"email\",\n        slug: \"letter-without-paper-travels-without-postman\",\n        question: \"I am a letter without paper, delivered without a postman, and arrive in an instant. I am read but I am never touched. What am I?\",\n        answer: \"An Email\",\n        explanation: \"An email is a digital message — no paper, no postman required. It arrives almost instantaneously anywhere in the world. It is read on screen but is never physically handled.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\"\n        ]\n    },\n    {\n        id: \"selfie\",\n        slug: \"portrait-where-subject-is-photographer\",\n        question: \"I am a portrait, but the subject is also the photographer. I am taken with an outstretched arm. I am shared more than any other type of photograph. What am I?\",\n        answer: \"A Selfie\",\n        explanation: \"A selfie is a self-portrait photograph taken by the subject themselves — using a front-facing camera or by holding the phone at arm's length. Billions are shared on social media every day.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\",\n            \"photography\"\n        ]\n    },\n    {\n        id: \"meme\",\n        slug: \"born-screen-spreads-like-virus\",\n        question: \"I am born on a screen and spread like a virus. I can make millions laugh or destroy a reputation. I am impossible to stop once I am loose. What am I?\",\n        answer: \"A Meme\",\n        explanation: \"Internet memes originate online and spread virally through social media. A funny meme can achieve global reach in hours. A damaging meme about a person can ruin their reputation — and once online, they are nearly impossible to fully erase.\",\n        category: \"modern\",\n        difficulty: \"medium\",\n        tags: [\n            \"technology\",\n            \"modern\",\n            \"culture\"\n        ]\n    },\n    {\n        id: \"podcast\",\n        slug: \"radio-show-no-radio-no-schedule\",\n        question: \"I am a radio show with no radio and no fixed schedule. I talk to millions but I am never live. I wait for you whenever you are ready. What am I?\",\n        answer: \"A Podcast\",\n        explanation: \"A podcast is an audio programme distributed digitally — no radio required. It is pre-recorded, not live. And unlike broadcast radio, it is available on demand whenever the listener chooses to tune in.\",\n        category: \"modern\",\n        difficulty: \"easy\",\n        tags: [\n            \"technology\",\n            \"modern\",\n            \"media\"\n        ]\n    }\n];\nconst categories = [\n    {\n        slug: \"classic\",\n        label: \"Classic\",\n        description: \"Time-honoured riddles passed down through generations\"\n    },\n    {\n        slug: \"wordplay\",\n        label: \"Wordplay\",\n        description: \"Riddles that play with language, puns, and double meanings\"\n    },\n    {\n        slug: \"lateral\",\n        label: \"Lateral Thinking\",\n        description: \"Riddles that require thinking completely outside the box\"\n    },\n    {\n        slug: \"abstract\",\n        label: \"Abstract\",\n        description: \"Riddles about ideas, emotions, and intangible things\"\n    },\n    {\n        slug: \"modern\",\n        label: \"Modern\",\n        description: \"Riddles with a contemporary, technology-age twist\"\n    }\n];\nconst difficulties = [\n    \"easy\",\n    \"medium\",\n    \"hard\"\n];\nfunction getRiddleBySlug(slug) {\n    return riddles.find((r)=>r.slug === slug) || null;\n}\nfunction getRiddlesByCategory(category) {\n    return riddles.filter((r)=>r.category === category);\n}\nfunction getDailyRiddle() {\n    const day = Math.floor(Date.now() / 86400000);\n    return riddles[day % riddles.length];\n}\nfunction getRelatedRiddles(riddle, count = 3) {\n    return riddles.filter((r)=>r.id !== riddle.id && (r.category === riddle.category || r.difficulty === riddle.difficulty)).slice(0, count);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./data/riddles.js\n");

